"""Provenance API — opt-in sync of authorship records, rollups, file tree, and per-line blame."""
from __future__ import annotations

from fastapi import APIRouter, Depends
from sqlalchemy import select
from sqlalchemy.orm import Session

from backend.app.db.models import ProvenanceRecordORM
from backend.app.db.session import get_db
from backend.app.security.secret_firewall import redact
from shared.schema.provenance import ProvenanceRecord, TraceSummary

router = APIRouter(prefix="/trace", tags=["trace"])


@router.post("/records")
def ingest_records(records: list[ProvenanceRecord], db: Session = Depends(get_db)):
    """Sync authorship records from a developer's machine (opt-in). Prompts are re-redacted
    defensively on ingest, so a raw secret can never land in the DB."""
    for r in records:
        db.merge(ProvenanceRecordORM(
            record_id=r.record_id, repo=r.repo, commit_sha=r.commit_sha,
            file_path=r.file_path, line_start=r.line_start, line_end=r.line_end,
            author_type=r.author_type.value, model=r.model, agent=r.agent.value,
            session_id=r.session_id, prompt_ref=r.prompt_ref,
            prompt_redacted=redact(r.prompt_redacted) if r.prompt_redacted else None,
            content=r.content,
            human_edit_ratio=r.human_edit_ratio, reviewed_by=r.reviewed_by,
            reviewed_at=r.reviewed_at, created_at=r.created_at, bound_at=r.bound_at,
        ))
    db.commit()
    return {"ingested": len(records)}


def _records_for(db: Session, repo: str):
    return db.execute(
        select(ProvenanceRecordORM).where(ProvenanceRecordORM.repo == repo)
    ).scalars().all()


@router.get("/summary")
def repo_summary(repo: str, db: Session = Depends(get_db)) -> TraceSummary:
    s = TraceSummary(repo=repo)
    for r in _records_for(db, repo):
        span = max(1, r.line_end - r.line_start + 1)
        s.total_lines += span
        if r.author_type == "ai":
            s.ai_lines += span
            if not r.reviewed_by:
                s.unreviewed_ai_lines += span
        elif r.author_type == "hybrid":
            s.hybrid_lines += span
        else:
            s.human_lines += span
        if r.model:
            s.by_model[r.model] = s.by_model.get(r.model, 0) + span
        s.by_agent[r.agent] = s.by_agent.get(r.agent, 0) + span
    return s


@router.get("/tree")
def file_tree(repo: str, db: Session = Depends(get_db)):
    """Per-file authorship rollup for the file-tree sidebar."""
    by_file: dict[str, dict] = {}
    for r in _records_for(db, repo):
        span = max(1, r.line_end - r.line_start + 1)
        f = by_file.setdefault(r.file_path, {"path": r.file_path, "lines": 0, "ai_lines": 0, "unreviewed": 0})
        f["lines"] = max(f["lines"], r.line_end)
        if r.author_type in ("ai", "hybrid"):
            f["ai_lines"] += span
            if not r.reviewed_by:
                f["unreviewed"] += span
    return {"repo": repo, "files": sorted(by_file.values(), key=lambda x: x["path"])}


@router.get("/file")
def file_blame(repo: str, path: str, db: Session = Depends(get_db)):
    """Per-line blame for one file: each line tagged with who authored it. Reconstructed
    from the file's stored record spans (the web equivalent of `gitly trace <file>`)."""
    rows = sorted(
        [r for r in _records_for(db, repo) if r.file_path == path],
        key=lambda r: r.line_start,
    )
    lines: list[dict] = []
    for r in rows:
        body = (r.content or "").split("\n") if r.content else [""] * (r.line_end - r.line_start + 1)
        for i, text in enumerate(body):
            ln = r.line_start + i
            if ln > r.line_end:
                break
            lines.append({
                "line_no": ln,
                "content": text,
                "author_type": r.author_type,
                "model": r.model,
                "agent": r.agent,
                "reviewed": bool(r.reviewed_by),
                "human_edit_ratio": r.human_edit_ratio,
                "prompt": r.prompt_redacted,
                "commit_sha": r.commit_sha[:8],
            })
    return {"path": path, "lines": lines}


@router.get("/records")
def list_records(repo: str, db: Session = Depends(get_db)):
    rows = db.execute(
        select(ProvenanceRecordORM).where(ProvenanceRecordORM.repo == repo).limit(500)
    ).scalars().all()
    return [
        {
            "file_path": r.file_path,
            "commit_sha": r.commit_sha[:8],
            "author_type": r.author_type,
            "model": r.model,
            "agent": r.agent,
            "human_edit_ratio": r.human_edit_ratio,
            "reviewed": bool(r.reviewed_by),
            "lines": f"{r.line_start}-{r.line_end}",
        }
        for r in rows
    ]

export async function git(cwd: string, args: string[], env?: Record<string, string>): Promise<string> {
  const { stdout } = await exec("git", args, {
    cwd,
    maxBuffer: 16 * 1024 * 1024,
    env: env ? { ...process.env, ...env } : undefined,
  });
  return stdout;
}
export async function repoRoot(cwd: string): Promise<string> {
  try { return (await git(cwd, ["rev-parse", "--show-toplevel"])).trim(); } catch { return cwd; }
}
export async function repoName(cwd: string): Promise<string> {
  return (await repoRoot(cwd)).split("/").filter(Boolean).pop() || "repo";
}
export async function currentBranch(cwd: string): Promise<string> {
  try { return (await git(cwd, ["rev-parse", "--abbrev-ref", "HEAD"])).trim(); } catch { return ""; }
}
export const PROTECTED = /^(main|master|develop|release)$/;

// ---- secret redaction (mirror of backend/sdk) ----
const PATTERNS: [string, RegExp][] = [
  ["aws_access_key_id", /AKIA[0-9A-Z]{16}/g],
  ["github_token", /gh[pousr]_[A-Za-z0-9]{36,}/g],
  ["anthropic_key", /sk-ant-[A-Za-z0-9_-]{20,}/g],
  ["openai_key", /sk-[A-Za-z0-9]{20,}/g],
  ["private_key", /-----BEGIN [A-Z ]*PRIVATE KEY-----/g],
  ["jwt", /eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}/g],
  ["generic", /(?:api[_-]?key|secret|token|password)\s*[:=]\s*['"][^'"]{12,}['"]/gi],
];
export function redact(text: string): string {
  let out = text || "";
  for (const [kind, re] of PATTERNS) out = out.replace(re, `‹redacted:${kind}›`);
  return out;
}
const sha = (s: string) => createHash("sha256").update(s || "").digest("hex");

// ---- backend api ----
async function api(path: string, init?: RequestInit): Promise<any> {
  const r = await fetch(`${API}${path}`, init);
  if (!r.ok) throw new Error(`gitly API ${path} -> HTTP ${r.status}`);
  return r.json();
}
const post = (path: string, body: unknown) =>
  api(path, { method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body) });

export const scanSecrets = (text: string) => post("/copilot/scan", { text });
export const analyzeDiff = (diff: string) => post("/lens/analyze", { diff });
export const traceSummary = (repo: string) => api(`/trace/summary?repo=${encodeURIComponent(repo)}`);
export const shrinkJob = (repo: string, base: string, head: string) => post("/shrink/jobs", { repo, base, head });

// ---- provenance ledger ----
export async function recordAuthorship(
  root: string,
  ev: { file_path: string; line_start: number; line_end: number; proposed_text?: string; model?: string; agent?: string; prompt?: string; session_id?: string },
  ledger = ".gitly/provenance",
): Promise<string> {
  const dir = join(root, ledger);
  await mkdir(dir, { recursive: true });
  const event_id = sha(`${ev.file_path}:${ev.line_start}:${Date.now()}:${Math.random()}`).slice(0, 32);
  const rec = {
    event_id,
    repo: root.split("/").filter(Boolean).pop() || "repo",
    file_path: ev.file_path,
    content_hash: sha(ev.proposed_text || ""),
    line_start: ev.line_start,
    line_end: ev.line_end,
    author_type: "ai",
    model: ev.model ?? null,
    agent: ev.agent ?? "unknown",
    session_id: ev.session_id ?? null,
    prompt_ref: ev.prompt ? sha(ev.prompt).slice(0, 16) : null,
    prompt_redacted: ev.prompt ? redact(ev.prompt) : null,
    proposed_text: redact(ev.proposed_text || ""),
    created_at: new Date().toISOString().slice(0, 19),
  };
  await appendFile(join(dir, `${new Date().toISOString().slice(0, 10)}.jsonl`), JSON.stringify(rec) + "\n", "utf8");
  return event_id;
}

// ---- absorb: fold working changes into the right earlier commit(s) + re-stack ----
async function earliestOf(cwd: string, shas: string[]): Promise<string> {
  const order = (await git(cwd, ["log", "--format=%H", "-n", "300"])).split("\n").map((s) => s.trim());
  let best = shas[0], bestIdx = -1;
  for (const s of shas) {
    const i = order.indexOf(s);
    if (i > bestIdx) { bestIdx = i; best = s; }  // larger index = older commit
  }
  return best;
}

export async function absorb(cwd: string, into?: string): Promise<string> {
  if (!(await git(cwd, ["status", "--porcelain"])).trim()) return "Nothing to absorb — the working tree is clean.";
  const branch = await currentBranch(cwd);
  if (PROTECTED.test(branch)) return `Refusing to absorb on protected branch '${branch}'. Switch to a feature branch first.`;

  const changed = (await git(cwd, ["diff", "HEAD", "--name-only"])).split("\n").map((s) => s.trim()).filter(Boolean);
  if (!changed.length) return "Only new/untracked files to commit — nothing to absorb. Use gitly_safe_commit.";

  const upstream = (await git(cwd, ["rev-parse", "--abbrev-ref", "--symbolic-full-name", "@{u}"]).catch(() => "")).trim();
  const since = upstream ? `${upstream}..HEAD` : "";

  // Each changed file -> the last local commit that touched it (or an explicit `into`).
  const targets: Record<string, string[]> = {};
  for (const f of changed) {
    let target = into || "";
    if (!target) {
      const args = ["log", "-n", "1", "--format=%H"];
      if (since) args.push(since);
      args.push("--", f);
      target = (await git(cwd, args)).trim();
    }
    if (!target) return `No local commit found that touches "${f}". Commit it first (gitly_safe_commit) or pass \`into\`.`;
    (targets[target] ||= []).push(f);
  }

  // Never rewrite published history.
  if (upstream) {
    for (const t of Object.keys(targets)) {
      if ((await git(cwd, ["branch", "-r", "--contains", t]).catch(() => "")).trim()) {
        return `Target ${t.slice(0, 8)} is already pushed — refusing to rewrite published history.`;
      }
    }
  }

  // One fixup commit per target (stage only that target's files).
  for (const [t, fs] of Object.entries(targets)) {
    await git(cwd, ["reset", "-q"]);
    await git(cwd, ["add", "--", ...fs]);
    await git(cwd, ["commit", "-q", "--fixup", t]);
  }

  // Non-interactive autosquash rebase from just before the earliest target.
  const earliest = await earliestOf(cwd, Object.keys(targets));
  const hasParent = await git(cwd, ["rev-parse", "--verify", `${earliest}^`]).then(() => true).catch(() => false);
  const base = hasParent ? [`${earliest}^`] : ["--root"];
  try {
    await git(cwd, ["rebase", "-i", "--autosquash", ...base], { GIT_SEQUENCE_EDITOR: "true", GIT_EDITOR: "true" });
  } catch {
    await git(cwd, ["rebase", "--abort"]).catch(() => {});
    return "Could not absorb cleanly (rebase conflict). Aborted — your commits and changes are untouched.";
  }
  const nFiles = Object.values(targets).reduce((a, b) => a + b.length, 0);
  const tlist = Object.keys(targets).map((t) => t.slice(0, 8)).join(", ");
  return `Absorbed ${nFiles} file change(s) into ${Object.keys(targets).length} commit(s): ${tlist}

def _git(cwd: str, *args: str, env: dict | None = None, check: bool = True) -> str:
    p = subprocess.run(
        ["git", "-C", str(cwd), *args],
        capture_output=True, text=True, env={**os.environ, **(env or {})},
    )
    if check and p.returncode != 0:
        raise GitError(p.stderr.strip())
    return p.stdout

:
    try:
        out = subprocess.run(
            ["git", "rev-parse", "--show-toplevel"], capture_output=True, text=True, check=True
        )
        return Path(out.stdout.strip())
    except Exception:
        return Path.cwd()


def _tracked_files(root: Path) -> list[str]:
    out = subprocess.run(["git", "-C", str(root), "ls-files"], capture_output=True, text=True)
    return out.stdout.splitlines()


def _tag(ln) -> str:
    if ln.author_type.value == "human":
        return "human"
    badge = ln.model or ln.agent.value
    mark = "~" if ln.inferred else ""           # ~ = inferred, not recorded
    rev = "" if ln.reviewed else " !unreviewed"
    return f"AI:{badge}{mark}{rev}"


def _render_summary(s) -> str:
    pct = (100 * s.ai_lines / s.total_lines) if s.total_lines else 0
    rows = [
        f"repo: {s.repo}",
        f"lines: {s.total_lines}   ai: {s.ai_lines} ({pct:.0f}%)   human: {s.human_lines}   hybrid: {s.hybrid_lines}",
        f"unreviewed AI lines: {s.unreviewed_ai_lines}",
    ]
    if s.by_model:
        rows.append("by model: " + ", ".join(f"{k}={v}" for k, v in s.by_model.items()))
    return "\n".join(rows)


@trace_app.callback(invoke_without_command=True)
def trace_default(
    ctx: typer.Context,
    file: str = typer.Argument(None, help="File to trace (blame-style provenance)."),
    summary: bool = typer.Option(False, "--summary", help="Repo rollup instead of per-line."),
):
    if ctx.invoked_subcommand is not None:
        return
    root = _repo_root()
    if summary or not file:
        files = [file] if file else _tracked_files(root)
        all_lines = []
        for f in files:
            try:
                all_lines += trace_file(root, f)
            except Exception:
                continue
        typer.echo(_render_summary(summarize(all_lines, repo=root.name)))
        return
    for ln in trace_file(root, file):
        typer.echo(f"{ln.line_no:>5}  {_tag(ln):<26} {ln.content}")


@app.command()
def scan(staged: bool = typer.Option(False, "--staged", help="Scan staged changes (for a pre-commit hook).")):
    """Secret firewall: block secrets before they're committed."""
    root = _repo_root()
    if staged:
        text = subprocess.run(
            ["git", "-C", str(root), "diff", "--cached"], capture_output=True, text=True
        ).stdout
    else:
        text = sys.stdin.read()
    findings = secret_scan(text)
    if findings:
        for f in findings:
            typer.secho(f"  secret[{f.kind}] line {f.line_no}: {f.match[:12]}…", fg="red")
        typer.secho(f"x {len(findings)} potential secret(s) — commit blocked.", fg="red", err=True)
        raise typer.Exit(1)
    typer.secho("ok: no secrets detected", fg="green")


@app.command()
def shrink(
    base: str = typer.Argument(..., help="Base ref (e.g. main)"),
    head: str = typer.Argument("HEAD", help="Head ref"),
    repo: str = typer.Option(".", "--repo", help="Path to the git repo"),
    strength: str = typer.Option("balanced", "--strength", help="gentle | balanced | aggressive"),
    max_lines: int = typer.Option(0, "--max-lines", help="Override max lines/slice (0 = use --strength)"),
    write_refs: bool = typer.Option(False, "--write-refs", help="Create shrink/* branches for each slice"),
    llm: bool = typer.Option(False, "--llm", help="Use the LLM labeler (needs GITLY_ANTHROPIC_API_KEY)"),
):
    """Split a PR (base..head) into a verified stack of small sub-PRs."""
    from backend.app.engines.shrink.planner.planner import PlanOptions
    from backend.app.engines.shrink.service import shrink as run_shrink

    presets = {
        "gentle": dict(max_lines=1500, min_lines=300, max_slices=2),
        "balanced": dict(max_lines=400, min_lines=40, max_slices=6),
        "aggressive": dict(max_lines=120, min_lines=1, max_slices=20),
    }
    preset = dict(presets.get(strength, presets["balanced"]))
    if max_lines:
        preset["max_lines"] = max_lines
    root = repo if repo != "." else str(_repo_root())
    res = run_shrink(root, base, head, opts=PlanOptions(**preset), write_refs=write_refs, prefer_llm=llm)
    typer.echo(f"{res.original_lines} lines / {res.original_files} files  ->  {len(res.slices)} slices")
    for s in res.slices:
        dep = f"  (after #{', #'.join(map(str, s.depends_on))})" if s.depends_on else ""
        typer.echo(f"  #{s.order}  {s.title}  [{s.lines} ln / {s.files} files]{dep}")
        if s.intent:
            typer.echo(f"        {s.intent}")
    if res.completeness_ok:
        typer.secho("ok: completeness verified — tree(base + slices) == tree(head)", fg="green")
    else:
        typer.secho("x: completeness FAILED — stack not shipped", fg="red", err=True)
        raise typer.Exit(1)
    if write_refs and res.materialized:
        typer.echo("branches:")
        for sc in res.materialized.slices:
            typer.echo(f"  {sc.branch}  ({sc.commit_sha[:10]})")


